const clamp = (v, min = 0, max = 100) => Math.min(max, Math.max(min, v))
const num = (v, d = 1) => typeof v === 'number' && Number.isFinite(v) ? v.toFixed(d) : '-'
const role = p => /C/.test(p||'') ? 'big' : /PF/.test(p||'') ? 'forward' : /SF/.test(p||'') ? 'wing' : 'guard'
const thresholds = { ppg:[12,20], ts:[55,62], efg:[50,57], usg:[18,28], astTo:[1.2,2.2], per:[18,25], blkPct:[1.5,3.5], stlPct:[1.4,2.6], ftp:[70,80], guard:{rpg:[3,5],apg:[3,6],fgp:[42,48],threep:[34,38]}, wing:{rpg:[4,6.5],apg:[2,4],fgp:[44,51],threep:[34,38]}, forward:{rpg:[5.5,8],apg:[1.8,3.5],fgp:[47,54],threep:[33,37]}, big:{rpg:[7,10],apg:[1.2,2.8],fgp:[52,60],threep:[31,36]} }
const quality = (k, v, p) => { if (typeof v !== 'number') return COLORS.miss; const r = role(p.position); const [a,s] = thresholds[r]?.[k] || thresholds[k] || [0,1]; return v >= s ? COLORS.strong : v >= a ? COLORS.avg : COLORS.weak }
const metricMax = (k, fallback) => Math.max(fallback, ...ALL_PROSPECTS.map(p=>p.stats?.[k]).filter(v=>typeof v==='number'))
const metricNote = (k, v, p, fallbackMax) => { if (typeof v !== 'number') return 'sem dado confiavel na base'; const r=role(p.position), roleLabel=r === 'big' ? 'big' : r === 'forward' ? 'forward' : r === 'wing' ? 'ala' : 'guard', [avg,strong]=thresholds[r]?.[k] || thresholds[k] || [fallbackMax*.45,fallbackMax*.7], max=metricMax(k,fallbackMax); if (v >= strong) return `nivel alto para ${roleLabel} · topo DB ${num(max)}`; if (v >= avg) return `faixa media/boa · topo DB ${num(max)}`; return `abaixo da referencia · topo DB ${num(max)}` }
const profileHeadline = p => PROFILE_TITLES[p.name] || (() => { const s=p.stats||{}; if (p.tier === 'ELITE') return 'Talento de topo com caminho para estrela'; if ((s.ts||0) >= 60 && (s.usg||0) >= 24) return 'Criador eficiente de alto volume'; if ((s.threep||0) >= 38) return 'Especialista de spacing NBA'; if ((s.blkPct||0) >= 3 || (s.rpg||0) >= 9) return 'Interior de impacto fisico'; if ((s.astTo||0) >= 2 || (s.apg||0) >= 5) return 'Condutor secundario de rotação'; return 'Perfil NBA em desenvolvimento' })()
const inches = v => { const m = String(v||'').match(/(\d+)'(?:([\d.]+))?/); return m ? Number(m[1])*12 + Number(m[2]||0) : null }
const heightM = v => { const i = inches(v); return i == null ? (v || '-') : (Math.round(i*2.54)/100).toFixed(2).replace('.', ',') + ' m' }
const wings = v => { const i = inches(v); return i == null ? (v || '-') : Math.round(i*2.54) + ' cm' }
const weight = v => { const m = String(v||'').match(/[\d.]+/); return m ? Math.round(Number(m[0])*.45359237) + ' kg' : (v || '-') }
const initials = n => String(n||'').split(' ').filter(Boolean).slice(0,2).map(x=>x[0]).join('').toUpperCase()
const validOutcomeScore = value => typeof value === 'number' && Number.isFinite(value) && value >= 35
const manualEvaluation = p => p?.scouting?.evaluation || null
const manualFloorScore = p => { const score = manualEvaluation(p)?.floor?.score; return validOutcomeScore(score) ? score : null }
const manualCeilingScore = p => { const score = manualEvaluation(p)?.ceiling?.score; return validOutcomeScore(score) ? score : null }
function estimateOutcomeScores(p) { const s=p.stats||{}, floor=Math.round(clamp(38+(s.ppg||0)*.7+(s.ts||50)*.35,35,92)), ceiling=Math.round(clamp(floor+14+(p.tier==='ELITE'?8:4),45,98)); return { floor: Math.min(floor, ceiling-1), ceiling } }
function resolveOutcomeScores(p) { const estimated=estimateOutcomeScores(p), mf=manualFloorScore(p), mc=manualCeilingScore(p); let floor=mf ?? estimated.floor, ceiling=mc ?? estimated.ceiling; if(mf !== null && mc === null) ceiling=Math.max(estimated.ceiling, floor + (p.tier==='ELITE'?20:14)); if(mc !== null && mf === null) floor=Math.min(estimated.floor, ceiling - 10); floor=Math.round(clamp(floor,35,98)); ceiling=Math.round(clamp(ceiling,36,99)); if(floor >= ceiling) floor=Math.max(35, ceiling-1); return { floor, ceiling } }
const attrValue = (p, label) => { const attrs=p.scouting?.attributes||{}, stats=p.stats||{}, k=String(label||'').toLowerCase(); if(k.includes('shoot')) return attrs.Shooting || clamp((stats.threep||25)/4.5,1,10); if(k.includes('score')) return clamp((stats.ppg||12)/2.8,1,10); if(k.includes('play')||k.includes('connect')) return attrs.Playmaking || clamp((stats.apg||2)*1.35,1,10); if(k.includes('defend')) return attrs.Defense || clamp(Math.max(stats.stlPct||0,stats.blkPct||0)*2.1,1,10); if(k.includes('rebound')) return attrs.Rebounding || clamp((stats.rpg||4)/1.2,1,10); if(k.includes('motor')) return attrs.Athleticism || 7; return 6 }
function getPlayerArchetype(p) { const s=p.stats||{}, r=role(p.position); if((s.ppg||0)>=18 && (s.usg||0)>=24) return r==='guard'?'Primary Shot Creator':'Go-To Scoring Forward'; if((s.threep||0)>=37 && /PF|C/.test(p.position||'')) return 'Stretch Big'; if((s.blkPct||0)>=3.5) return 'Defensive Anchor'; if((s.apg||0)>=4 || (s.astTo||0)>=2) return 'Connector / Playmaker'; if(/SG|SF/.test(p.position||'') && Math.max(s.stlPct||0,s.blkPct||0)>=2) return 'Two-Way Wing'; if((s.rpg||0)>=8) return 'High-Motor Forward'; return r==='guard'?'Combo Guard':r==='big'?'Modern Big':'Two-Way Prospect' }
function getDraftRange(p) { if((p.rank||99)<=5) return 'Projected: Top 5'; if((p.rank||99)<=14) return 'Projected: Lottery'; if((p.rank||99)<=30) return 'Projected: First Round'; return 'Projected: Second Round' }
function getPlayerComp(p) { const s=p.stats||{}, r=role(p.position), floor=r==='guard'?'Rotation Guard':r==='big'?'Rotation Big':'Rotation Wing'; if((s.threep||0)>=38) return ['Ceiling: premium spacer', 'Floor: '+floor]; if((s.ppg||0)>=20) return ['Ceiling: primary scorer', 'Floor: microwave scorer']; if((s.blkPct||0)>=3.5) return ['Ceiling: defensive anchor', 'Floor: rim protection specialist']; return ['Ceiling: '+(p.tier==='ELITE'?'franchise upside':'starter upside'), 'Floor: '+floor] }
function getOverviewCopy(p) { const s=p.stats||{}, sub=(s.ts||0)>=60?'Produz volume com eficiência acima da curva.':(s.threep||0)>=37?'O arremesso cria um caminho claro de tradução.':Math.max(s.stlPct||0,s.blkPct||0)>=3?'Defesa e ferramentas fisicas puxam o valor inicial.':'Perfil que combina contexto, desenvolvimento e papel NBA.'; return { headline: profileHeadline(p), subheadline: getPlayerArchetype(p)+' / '+sub, body: p.scouting?.notes || 'Leitura baseada em producao, tier e indicadores disponiveis. O encaixe ideal depende de papel ofensivo claro e paciencia no desenvolvimento.' } }
function getAttributeGrade(value) { if(value>=8.5) return 'Elite'; if(value>=7) return 'Plus'; if(value>=5.6) return 'Solid'; return 'Question' }
function getAttributeCopy(attribute, p) { const s=p.stats||{}, k=String(attribute||'').toLowerCase(); if(k.includes('shoot')) return typeof s.threep==='number' ? num(s.threep)+'% de 3PT como termometro de spacing.' : 'Traducao ligada a volume e consistencia do jumper.'; if(k.includes('score')) return typeof s.ppg==='number' ? num(s.ppg)+' PPG mostram o peso ofensivo atual.' : 'Valor depende de criacao propria e vantagem fisica.'; if(k.includes('play')) return typeof s.apg==='number' ? num(s.apg)+' APG indicam leitura e criacao para terceiros.' : 'Precisa transformar leitura em vantagens consistentes.'; if(k.includes('defend')) return 'Atividade em roubos/tocos define o piso de impacto sem bola.'; if(k.includes('rebound')) return typeof s.rpg==='number' ? num(s.rpg)+' RPG contextualizam fisicalidade e motor.' : 'Rebote sera ponto chave para manter minutos.'; return 'Indicador qualitativo do pacote de ferramentas.' }
function getDominantAttribute(attrs={}) { return RADAR.map(a=>[a, typeof attrs[a]==='number'?attrs[a]:5]).sort((a,b)=>b[1]-a[1])[0] || ['-',0] }
function getWeakestAttribute(attrs={}) { return RADAR.map(a=>[a, typeof attrs[a]==='number'?attrs[a]:5]).sort((a,b)=>a[1]-b[1])[0] || ['-',0] }
function getNBATranslation(p) { const s=p.stats||{}, r=role(p.position); const roleText=(s.ppg||0)>=18?'Scorer secundario':r==='big'?'Big de rotação':r==='wing'?'Wing de rotação':'Guard de segunda unidade'; const fit=(s.threep||0)>=36?'Melhor ao lado de um primary creator':(s.apg||0)>=4?'Ideal com finalizadores e spacing':r==='big'?'Precisa de espacamento ao redor':'Funciona melhor em ritmo alto e transição'; const risk=(s.threep||0)<32?'Consistência do arremesso':(s.astTo||2)<1.2?'Tomada de decisão contra pressoes fisicas':(s.ts||60)<54?'Eficiência contra atletas NBA':'Definir papel sem perder agressividade'; return [['Papel inicial',roleText],['Fit ideal',fit],['Principal risco',risk]] }
function getStoryTags(p) { const s=p.stats||{}, tags=[]; if(p.tier==='ELITE') tags.push('Franchise Swing'); if((s.ppg||0)>=20) tags.push('Elite Scorer'); if((s.threep||0)>=37) tags.push('Shooting Swing'); if(Math.max(s.stlPct||0,s.blkPct||0)>=3) tags.push('Defensive Bet'); if((s.astTo||0)>=1.8 || (s.apg||0)>=4) tags.push('Playmaking Upside'); if((p.rank||99)>24) tags.push('Development Project'); if(!tags.length) tags.push('Safe Floor'); return tags.slice(0,5) }
function getDecisionProfile(p, floorOverride, ceilingOverride) { const resolved=resolveOutcomeScores(p), manualRisk=manualEvaluation(p)?.risk?.level, floor=typeof floorOverride==='number'?floorOverride:resolved.floor, ceiling=typeof ceilingOverride==='number'?ceilingOverride:resolved.ceiling, risk=manualRisk || (floor<50?'High':floor<60?'Moderate':'Low'); return [{label:'Projecao',value:getCeilingLabel(ceiling),tone:'#a79be8'},{label:'Papel inicial',value:getFloorLabel(floor),tone:'#8bbfe8'},{label:'Risco',value:risk,tone:risk==='High'?'#e8a6a6':risk==='Moderate'||risk==='Medium'?'#8bbfe8':'#6fbf9c'},{label:'Nota geral',value:String(Math.round((floor+ceiling)/2)),tone:p.accentColor||'#a79be8'}] }
