function getRadarCopy(attribute, type) { const k=String(attribute||'').toLowerCase(); if(type==='weak') { if(k.includes('shoot')) return 'A tradução depende de consistencia, volume e punicao a defesas mais fisicas.'; if(k.includes('rebound')) return 'Precisa evoluir no instinto, contato e posicionamento para fechar posses.'; if(k.includes('play')) return 'Ainda precisa acelerar leituras e reduzir decisões tardias contra pressoes.'; if(k.includes('defense')) return 'O ponto de atencao esta em sustentar impacto contra atletas NBA.'; return 'Area que pede desenvolvimento para estabilizar o papel NBA.' } if(k.includes('shoot')) return 'Espacamento, toque e confiança criam um caminho claro de impacto ofensivo.'; if(k.includes('play')) return 'Visao acima da media, leitura rapida e capacidade de criar vantagens.'; if(k.includes('defense')) return 'Ferramentas e atividade elevam o piso mesmo sem grande volume ofensivo.'; if(k.includes('rebound')) return 'Motor, fisico e presenca nos rebotes ajudam a sustentar minutos.'; return 'Ferramenta central que sustenta a avaliação geral do prospecto.' }
function getEditorialInsights(p) { const s=p.stats||{}; const production=(s.ppg||0)>=20?'Elite':(s.ppg||0)>=14?'Alta':'Funcional'; const consistency=(s.ts||0)>=60?'Alta':(s.ts||0)>=55?'Estavel':'Em construcao'; const trajectory=p.age<=19?'Ascendente':(p.rank||99)<=20?'Consolidada':'Situacional'; return [{label:'Producao ofensiva',value:production,Icon:BarChart3,color:'#a79be8'},{label:'Consistência',value:consistency,Icon:Crosshair,color:'#8bbfe8'},{label:'Trajetoria',value:trajectory,Icon:TrendingUp,color:'#6fbf9c'}] }
function getNBATranslationCards(p) { const base=getNBATranslation(p); const colors=['#a79be8','#8bbfe8','#e8a6a6']; const icons=[User,Puzzle,AlertTriangle]; const desc=['Traduz o primeiro papel que pode gerar minutos sem exigir protagonismo imediato.','Define o ecossistema ofensivo e defensivo que melhor acelera a tradução.','Ponto que mais pode limitar eficiência, minutos ou confiança no proximo nivel.']; return base.map(([label,value],i)=>({label,value,description:desc[i],color:colors[i],Icon:icons[i]})) }
function getDraftValueContext(p, currentPick) { const data=getDraftValue(p,currentPick), status=data[0], color=data[1], rank=p.rank||'-', pick=currentPick||p.rank||'-'; const text=status==='Steal'?'Valor acima da posicao atual do board.':status==='Reach'?'Aposta acima da expectativa atual de mercado.':'Valor alinhado a expectativa do board.'; return [{label:'RANK ESPERADO',value:'#'+rank,sub:'Top '+rank+' do Big Board',Icon:ListOrdered,color:'#a79be8'},{label:'MOCK POSITION',value:'#'+pick,sub:'Selecionado atualmente no '+pick+' pick',Icon:Target,color:'#8bbfe8'},{label:'VALUE',value:status,sub:text,Icon:Gem,color}] }
function getFloorLabel(score) { if(score < 40) return 'G-League'; if(score < 50) return 'Fundo de banco'; if(score < 60) return 'Rotacao'; if(score < 70) return 'Starter'; if(score < 85) return 'All-Star'; if(score < 90) return 'Franchise Player'; return 'MVP' }
